import React from 'react';
import { useTranslation } from 'react-i18next';

export default function WalletPage() {
  const { t } = useTranslation();
  return (
    <div className="page wallet-page">
      <div className="page-header"><h1>{t('nav.wallet')}</h1></div>
      <div className="page-content">
        <div className="wallet-card">
          <h3>{t('wallet.balance') || 'Balance'}</h3>
          <p className="balance-amount">$0.00</p>
          <button className="btn btn-primary">{t('wallet.addFunds') || 'Add Funds'}</button>
        </div>
        <div className="wallet-history">
          <h3>{t('wallet.transactionHistory') || 'History'}</h3>
          <p className="text-muted">{t('wallet.noTransactions') || 'No transactions yet'}</p>
        </div>
      </div>
    </div>
  );
}
